mapper.select:
SELECT su.id, su.username, su.email, su.phone, su.create_time, su.modify_time, su.is_deleted AS deleted, su.id AS role_id, sr.name AS role_name FROM sys_user su LEFT JOIN sys_user_role sur ON sur.user_id = su.id LEFT JOIN sys_role sr ON sr.id = sur.role_id
su.is_deleted = 0
AND (su.username LIKE CONCAT('%', #{dto.searchCondition}, '%') OR su.email LIKE CONCAT('%', #{dto.searchCondition}, '%') OR su.phone LIKE CONCAT('%', #{dto.searchCondition}, '%'))
AND sr.id = #{dto.roleId}
ORDER BY ${dto.sortCondition}
